{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem is a constrained optimization problem involving graph embedding (topological map) onto a grid. It requires finding a layout that preserves adjacency while maximizing empty cells. I will break this into graph representation, layout generation, and validation.",
  "helpers": [
    {
      "label": "graph_analyzer",
      "instructions": "Represent the colored city map as a graph where each colored region is a node. Define edges between nodes if their corresponding regions are adjacent. Identify the minimum number of nodes required to represent the connectivity and the constraints imposed by the colors."
    },
    {
      "label": "layout_optimizer",
      "instructions": "Given a graph of colored regions, find an embedding on a 50x50 grid such that all adjacent nodes in the graph are placed in adjacent cells (horizontally or vertically) on the grid. The goal is to minimize the total number of cells occupied by colored regions to maximize the number of empty cells, while ensuring no two different colored regions occupy the same cell and all connectivity constraints are met."
    },
    {
      "label": "validator",
      "instructions": "Verify a proposed 50x50 grid layout. Check that: 1. All original color-adjacency relations are preserved. 2. No connectivity constraints are violated. 3. The number of empty cells is calculated correctly. 4. The grid dimensions are exactly 50x50."
    }
  ],
  "synthesis_brief": "Combine the graph structure from the analyzer with the optimized grid layout from the optimizer. Use the validator to confirm the layout is legal and calculate the final score (E + 1) based on the empty cells found in the grid."
}

